import type { HTMLAttributes } from 'react';
export type SnackbarHorizontalType = 'left' | 'center' | 'right';
export type SnackbarVerticalType = 'top' | 'bottom';
export type SnackbarVariantType = 'elastic' | 'fixed';
export interface SnackbarButtonProps {
    label?: string;
    onClick?: () => void;
}
export interface SnackbarProps extends HTMLAttributes<HTMLDivElement> {
    /**
     * Текстовое содержимое
     */
    message: string;
    /**
     * Состояние: отображен / скрыт
     */
    open?: boolean;
    /**
     Тип отображения текста и кнопок для однострочного / многострочного компонента
     */
    variant?: SnackbarVariantType;
    /**
     * Количество времени перед скрытием в ms.
     */
    delay?: number;
    /**
     * Определяет положение слева | по центру | справа
     */
    horizontal?: SnackbarHorizontalType;
    /**
     * Определяет вертикальное положение вверху | внизу
     */
    vertical?: SnackbarVerticalType;
    /**
     * Объект кнопки с названием и действием при клике
     */
    action?: SnackbarButtonProps;
    /**
     * Отображать кнопку закрытия
     */
    closeButton?: boolean;
    /**
     * Обработчик события закрытия
     */
    onClose?: () => void;
    /**
     * Передаваемый класс корневому компоненту для последующей стилизации
     */
    className?: string;
}
